{
  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "5 3\n1 2 3 4 5\n",
      "output": "3\n",
      "notes": "Tests a basic case with a small number of disks."
    },
    {
      "name": "all_identical",
      "input": "4 2\n2 2 2 2\n",
      "output": "2\n",
      "notes": "Tests the case where all disk sizes are identical."
    },
    {
      "name": "single_disk",
      "input": "1 1\n10\n",
      "output": "10\n",
      "notes": "Tests the edge case with only one disk."
    },
    {
      "name": "no_disks",
      "input": "0 0\n\n",
      "output": "0\n",
      "notes": "Tests the edge case with no disks."
    },
    {
      "name": "large_numbers",
      "input": "5 3\n100000 200000 300000 400000 500000\n",
      "output": "300000\n",
      "notes": "Tests the case with large disk sizes."
    },
    {
      "name": "more_disks_than_needed",
      "input": "6 4\n1 2 3 4 5 6\n",
      "output": "4\n",
      "notes": "Tests the case where there are more disks than needed."
    },
    {
      "name": "descending_order",
      "input": "5 3\n5 4 3 2 1\n",
      "output": "3\n",
      "notes": "Tests the case with disks in descending order."
    },
    {
      "name": "negative_sizes",
      "input": "3 2\n-1 -2 -3\n",
      "output": "-1\n",
      "notes": "Tests the case with negative disk sizes."
    }
  ],
  "assumptions": "Input will always be valid integers, and the number of disks will not exceed the specified limits.",
  "notes": "Ensure to handle edge cases gracefully."
}
